using System;
using System.Runtime.CompilerServices;
using System.Threading.Tasks;

namespace Microsoft.VisualStudio.TestTools.UnitTesting;

/// <summary>
/// This attribute is used to mark test methods.
/// </summary>
/// <remarks>
/// <list type="bullet">
/// <item>
/// <description>
/// When using other attributes like <see cref="T:Microsoft.VisualStudio.TestTools.UnitTesting.DataRowAttribute" /> or <see cref="T:Microsoft.VisualStudio.TestTools.UnitTesting.DynamicDataAttribute" />,
/// the use of <see cref="T:Microsoft.VisualStudio.TestTools.UnitTesting.TestMethodAttribute" /> is still required.
/// </description>
/// </item>
/// <item>
/// <description>
/// Test methods must be:
/// <list type="bullet">
/// <item><description>public, or if <see cref="T:Microsoft.VisualStudio.TestTools.UnitTesting.DiscoverInternalsAttribute" /> is used then it can be internal.</description></item>
/// <item><description>not static</description></item>
/// <item><description>not generic</description></item>
/// <item><description>not abstract</description></item>
/// <item><description>return type is either <see langword="void" />, <see cref="T:System.Threading.Tasks.Task" />, or <see cref="T:System.Threading.Tasks.ValueTask" />. If <see langword="void" />, then it shouldn't be <see langword="async" />.</description></item>
/// </list>
/// </description>
/// </item>
/// </list>
/// </remarks>
[AttributeUsage(AttributeTargets.Method, Inherited = false)]
public class TestMethodAttribute : Attribute
{
	/// <summary>
	/// Gets or sets display name for the test.
	/// </summary>
	public string? DisplayName { get; set; }

	/// <summary>
	/// Gets or sets the strategy for unfolding parameterized tests.
	/// </summary>
	public TestDataSourceUnfoldingStrategy UnfoldingStrategy { get; set; }

	/// <summary>
	/// Gets the file path that declares the attribute.
	/// </summary>
	public string DeclaringFilePath { get; }

	/// <summary>
	/// Gets the line number within <see cref="P:Microsoft.VisualStudio.TestTools.UnitTesting.TestMethodAttribute.DeclaringFilePath" /> that declares the attribute.
	/// </summary>
	public int? DeclaringLineNumber { get; }

	/// <summary>
	/// Initializes a new instance of the <see cref="T:Microsoft.VisualStudio.TestTools.UnitTesting.TestMethodAttribute" /> class.
	/// </summary>
	public TestMethodAttribute([CallerFilePath] string callerFilePath = "", [CallerLineNumber] int callerLineNumber = -1)
	{
		DeclaringFilePath = callerFilePath;
		DeclaringLineNumber = ((callerLineNumber <= 0) ? ((int?)null) : new int?(callerLineNumber));
	}

	/// <summary>
	/// Executes a test method.
	/// </summary>
	/// <param name="testMethod">The test method to execute.</param>
	/// <returns>An array of TestResult objects that represent the outcome(s) of the test.</returns>
	/// <remarks>Extensions can override this method to customize running a TestMethod.</remarks>
